1	import { useCallback, useEffect, useState } from 'react';
2	import {
3	  Keyboard,
4	  Platform,
5	  StyleSheet,
6	  Text,
7	  TextInput,
8	  TouchableWithoutFeedback,
9	  View,
10	} from 'react-native';
11	import { BottomSheet } from '@/components/primitives/BottomSheet';
12	import { ButtonPrimary } from '@/components/primitives/Button';
13	import { useToast } from '@/components/primitives/Toast';
14	import { colors, radii, shadows, spacing } from '@/design/tokens';
15	import { textStyles } from '@/design/typography';
16	import { supabase } from '@/lib/supabase';
17	
18	// US-042 — Apply modal on campaign detail. Bottom sheet with an optional
19	// pitch field that calls the apply-to-listing edge function (US-041).
20	//
21	// Spec alignment (docs/design.md §4.3 + docs/tech-architecture.md §5.5):
22	// - Header copy "You're applying to" + listing title
23	// - Pitch (optional) text area with character counter (story AC: 280-char
24	//   cap; design.md mock shows 0/160 — story AC value used; see Spec gap
25	//   in progress.txt for US-042)
26	// - "By applying you confirm you'll follow the campaign rules." disclaimer
27	// - "Send application" CTA
28	//
29	// Edge-function field is `cover_note` per spec §5.5 / `applications.cover_note`
30	// column (the story AC says "pitch" but cover_note is canonical — same
31	// resolution as US-041's edge function).
32	//
33	// Response handling: 200 → onApplied; structured errors decoded via the
34	// FunctionsHttpError context Response (Codebase Pattern #98). For
35	// INELIGIBLE 403 the toast surfaces a one-line summary derived from the
36	// first failed condition; spec-defined 409 codes (LISTING_NOT_ACTIVE,
37	// LISTING_VERSION_CHANGED, ALREADY_APPLIED) and 404 each get their own
38	// toast. The parent reloads the listing for any state-changing error so
39	// the eligibility rail and CTA reflect the new server reality.
40	
41	const COVER_NOTE_MAX_LEN = 280;
42	
43	type SocialPlatform = 'tiktok' | 'instagram';
44	
45	type FailedCondition = {
46	  metric: string;
47	  platform: SocialPlatform | null;
48	  required: number | boolean;
49	  actual: number | boolean | null;
50	};
51	
52	type ApplySuccess = {
53	  application_id: string;
54	  listing_version_id: string;
55	};
56	
57	type ServerErrorBody = {
58	  error?: string;
59	  failed_conditions?: FailedCondition[];
60	  current_version_id?: string;
61	};
62	
63	export type ApplyFailure =
64	  | { kind: 'ineligible' }
65	  | { kind: 'version_changed' }
66	  | { kind: 'already_applied' }
67	  | { kind: 'not_active' }
68	  | { kind: 'not_found' };
69	
70	export type ApplySheetProps = {
71	  visible: boolean;
72	  listingId: string;
73	  listingTitle: string;
74	  onDismiss: () => void;
75	  onApplied: () => void;
76	  onServerStateChanged: (failure: ApplyFailure) => void;
77	};
78	
79	export function ApplySheet({
80	  visible,
81	  listingId,
82	  listingTitle,
83	  onDismiss,
84	  onApplied,
85	  onServerStateChanged,
86	}: ApplySheetProps) {
87	  const { show: showToast } = useToast();
88	  const [pitch, setPitch] = useState('');
89	  const [submitting, setSubmitting] = useState(false);
90	  const [keyboardEventHeight, setKeyboardEventHeight] = useState(0);
91	  const [inputFocused, setInputFocused] = useState(false);
92	
93	  // Reset the pitch + submitting flags whenever the sheet re-opens, so a prior
94	  // half-typed message doesn't leak into a fresh attempt.
95	  useEffect(() => {
96	    if (visible) {
97	      setPitch('');
98	      setSubmitting(false);
99	    }
100	  }, [visible]);
101	
102	  // KeyboardAvoidingView doesn't reliably push content up when nested inside a
103	  // RN <Modal> (the modal opens its own window so KAV's measured frame and the
104	  // keyboard's reported frame disagree). Listen to keyboard events directly
105	  // and apply the height as bottom padding so the CTA stays above the keyboard.
106	  // Fall back to a focus-driven estimate on iOS when the event misses or
107	  // arrives late (observed in nested-Modal contexts on the simulator).
108	  useEffect(() => {
109	    const showEvt = Platform.OS === 'ios' ? 'keyboardWillShow' : 'keyboardDidShow';
110	    const hideEvt = Platform.OS === 'ios' ? 'keyboardWillHide' : 'keyboardDidHide';
111	    const showSub = Keyboard.addListener(showEvt, (e) => {
112	      setKeyboardEventHeight(e.endCoordinates.height);
113	    });
114	    const hideSub = Keyboard.addListener(hideEvt, () => setKeyboardEventHeight(0));
115	    return () => {
116	      showSub.remove();
117	      hideSub.remove();
118	    };
119	  }, []);
120	  const FOCUS_KEYBOARD_FALLBACK = Platform.OS === 'ios' ? 336 : 0;
121	  const keyboardHeight = Math.max(
122	    keyboardEventHeight,
123	    inputFocused ? FOCUS_KEYBOARD_FALLBACK : 0,
124	  );
125	
126	  const onSubmit = useCallback(async () => {
127	    if (submitting) return;
128	    setSubmitting(true);
129	    const trimmed = pitch.trim();
130	    try {
131	      const { data, error } = await supabase.functions.invoke<ApplySuccess>(
132	        'apply-to-listing',
133	        {
134	          body: {
135	            listing_id: listingId,
136	            ...(trimmed.length > 0 ? { cover_note: trimmed } : {}),
137	          },
138	        },
139	      );
140	
141	      if (error) {
142	        const body = await readErrorBody(error);
143	        const failure = mapErrorBodyToFailure(body);
144	        if (failure) {
145	          showToast({
146	            message: toastForFailure(failure, body),
147	            variant: failure.kind === 'already_applied' ? 'info' : 'error',
148	          });
149	          onServerStateChanged(failure);
150	          return;
151	        }
152	        showToast({
153	          message: 'Could not send application. Try again.',
154	          variant: 'error',
155	        });
156	        return;
157	      }
158	
159	      if (!data?.application_id) {
160	        showToast({
161	          message: 'Could not send application. Try again.',
162	          variant: 'error',
163	        });
164	        return;
165	      }
166	
167	      onApplied();
168	    } catch (err) {
169	      console.error('apply-to-listing threw', err);
170	      showToast({
171	        message: 'Could not send application. Try again.',
172	        variant: 'error',
173	      });
174	    } finally {
175	      setSubmitting(false);
176	    }
177	  }, [pitch, listingId, submitting, showToast, onApplied, onServerStateChanged]);
178	
179	  const remaining = COVER_NOTE_MAX_LEN - pitch.length;
180	  const overLimit = remaining < 0;
181	
182	  return (
183	    <BottomSheet
184	      visible={visible}
185	      onDismiss={onDismiss}
186	      snapPoints={[0.85]}
187	      accessibilityLabel="Apply to campaign"
188	      testID="apply-sheet"
189	    >
190	      <View style={[styles.flex, { paddingBottom: keyboardHeight }]}>
191	        <View style={styles.header}>
192	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
193	            You&apos;re applying to
194	          </Text>
195	          <Text
196	            style={[textStyles.h1, { color: colors.ink }]}
197	            numberOfLines={2}
198	            testID="apply-sheet-title"
199	          >
200	            {listingTitle}
201	          </Text>
202	        </View>
203	
204	        <View style={styles.fieldGroup}>
205	          <View style={styles.labelRow}>
206	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>
207	              Pitch (optional)
208	            </Text>
209	            <Text
210	              style={[
211	                textStyles.caption,
212	                { color: overLimit ? colors.danger : colors.ink40 },
213	              ]}
214	              testID="apply-sheet-counter"
215	            >
216	              {pitch.length}/{COVER_NOTE_MAX_LEN}
217	            </Text>
218	          </View>
219	          <View
220	            style={[
221	              styles.inputWrap,
222	              shadows.hard,
223	              overLimit && styles.inputWrapError,
224	            ]}
225	          >
226	            <TextInput
227	              value={pitch}
228	              onChangeText={setPitch}
229	              onFocus={() => setInputFocused(true)}
230	              onBlur={() => setInputFocused(false)}
231	              placeholder="Why are you a fit?"
232	              placeholderTextColor={colors.ink40}
233	              multiline
234	              maxLength={COVER_NOTE_MAX_LEN + 40}
235	              style={[textStyles.body, styles.input]}
236	              accessibilityLabel="Pitch"
237	              testID="apply-sheet-pitch"
238	            />
239	          </View>
240	        </View>
241	
242	        <TouchableWithoutFeedback onPress={Keyboard.dismiss} accessible={false}>
243	          <Text style={[textStyles.caption, styles.disclaimer]}>
244	            By applying you confirm you&apos;ll follow the campaign rules.
245	          </Text>
246	        </TouchableWithoutFeedback>
247	
248	        <View style={styles.cta}>
249	          <ButtonPrimary
250	            label="Send application"
251	            onPress={onSubmit}
252	            loading={submitting}
253	            disabled={submitting || overLimit}
254	            testID="apply-sheet-submit"
255	          />
256	        </View>
257	      </View>
258	    </BottomSheet>
259	  );
260	}
261	
262	async function readErrorBody(
263	  error: unknown,
264	): Promise<ServerErrorBody | null> {
265	  const ctx = (error as { context?: unknown }).context;
266	  if (
267	    !ctx ||
268	    typeof ctx !== 'object' ||
269	    !('status' in ctx) ||
270	    typeof (ctx as { json?: unknown }).json !== 'function'
271	  ) {
272	    return null;
273	  }
274	  try {
275	    return (await (ctx as Response).json()) as ServerErrorBody;
276	  } catch {
277	    return null;
278	  }
279	}
280	
281	function mapErrorBodyToFailure(
282	  body: ServerErrorBody | null,
283	): ApplyFailure | null {
284	  if (!body?.error) return null;
285	  switch (body.error) {
286	    case 'INELIGIBLE':
287	      return { kind: 'ineligible' };
288	    case 'LISTING_VERSION_CHANGED':
289	      return { kind: 'version_changed' };
290	    case 'ALREADY_APPLIED':
291	      return { kind: 'already_applied' };
292	    case 'LISTING_NOT_ACTIVE':
293	      return { kind: 'not_active' };
294	    case 'LISTING_NOT_FOUND':
295	      return { kind: 'not_found' };
296	    default:
297	      return null;
298	  }
299	}
300	
301	function toastForFailure(
302	  failure: ApplyFailure,
303	  body: ServerErrorBody | null,
304	): string {
305	  switch (failure.kind) {
306	    case 'ineligible': {
307	      const first = body?.failed_conditions?.[0];
308	      return first
309	        ? `You no longer meet ${conditionLabel(first)}.`
310	        : 'You no longer meet this campaign\u2019s requirements.';
311	    }
312	    case 'version_changed':
313	      return 'This campaign was updated. Refreshing the details.';
314	    case 'already_applied':
315	      return 'You\u2019ve already applied to this campaign.';
316	    case 'not_active':
317	      return 'This campaign is no longer accepting applications.';
318	    case 'not_found':
319	      return 'This campaign is no longer available.';
320	  }
321	}
322	
323	function conditionLabel(f: FailedCondition): string {
324	  const platform = f.platform ? platformLabel(f.platform) : '';
325	  const base = metricLabel(f.metric);
326	  return platform ? `${platform} ${base}` : base;
327	}
328	
329	function platformLabel(p: SocialPlatform): string {
330	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
331	}
332	
333	function metricLabel(metric: string): string {
334	  switch (metric) {
335	    case 'min_followers':
336	      return 'minimum followers';
337	    case 'min_avg_views_last_n':
338	      return 'avg views (last 10)';
339	    case 'min_total_likes':
340	      return 'total likes';
341	    case 'min_videos_posted':
342	      return 'videos posted';
343	    case 'verified_only':
344	      return 'verified account';
345	    default:
346	      return metric;
347	  }
348	}
349	
350	const styles = StyleSheet.create({
351	  flex: { flex: 1 },
352	  header: {
353	    gap: spacing.xs,
354	    marginBottom: spacing.lg,
355	  },
356	  fieldGroup: {
357	    gap: spacing.sm,
358	  },
359	  labelRow: {
360	    flexDirection: 'row',
361	    justifyContent: 'space-between',
362	    alignItems: 'baseline',
363	  },
364	  inputWrap: {
365	    backgroundColor: colors.surface,
366	    borderRadius: radii.input,
367	    borderWidth: 2,
368	    borderColor: colors.ink,
369	  },
370	  inputWrapError: {
371	    borderColor: colors.danger,
372	  },
373	  input: {
374	    minHeight: 110,
375	    paddingHorizontal: spacing.base,
376	    paddingVertical: spacing.md,
377	    color: colors.ink,
378	    textAlignVertical: 'top',
379	  },
380	  disclaimer: {
381	    color: colors.ink70,
382	    marginTop: spacing.lg,
383	  },
384	  cta: {
385	    marginTop: 'auto',
386	    paddingTop: spacing.lg,
387	  },
388	});
